// EWS returns XML. n8n's HTTP Request node returns it as a string.
// This code node parses the SOAP response into a clean JSON structure.
// It handles both FindItem and GetItem and CreateItem responses.

const xmlData = $input.item.json.data ?? $input.item.json;

// Simple XML attribute/value extractor (no external deps needed)
function extractBetweenTags(xml, tag) {
  const closeTag = `</${tag}>`;
  let searchFrom = 0;
  while (true) {
    const start = xml.indexOf(`<${tag}`, searchFrom);
    if (start === -1) return null;
    const charAfter = xml[start + tag.length + 1];
    if (charAfter === '>' || charAfter === ' ') {
      const contentStart = xml.indexOf('>', start) + 1;
      const end = xml.indexOf(closeTag, contentStart);
      if (end === -1) return null;
      return xml.substring(contentStart, end).trim();
    }
    searchFrom = start + 1;
  }
}

function extractAll(xml, tag) {
  const results = [];
  let searchFrom = 0;
  while (true) {
    const start = xml.indexOf(`<${tag}`, searchFrom);
    if (start === -1) break;
    const charAfter = xml[start + tag.length + 1];
    if (charAfter !== '>' && charAfter !== ' ') {
      searchFrom = start + 1;
      continue;
    }
    const contentStart = xml.indexOf('>', start) + 1;
    const end = xml.indexOf(`</${tag}>`, contentStart);
    if (end === -1) break;
    results.push(xml.substring(contentStart, end).trim());
    searchFrom = end + `</${tag}>`.length;
  }
  return results;
}


function extractAttr(xml, tag, attr) {
  const tagStart = xml.indexOf(`<${tag}`);
  if (tagStart === -1) return null;
  const tagEnd = xml.indexOf('>', tagStart);
  const tagContent = xml.substring(tagStart, tagEnd);
  const attrMatch = tagContent.match(new RegExp(`${attr}="([^"]+)"`, 'i'));
  return attrMatch ? attrMatch[1] : null;
}

// Check for errors first
const responseCode = extractBetweenTags(xmlData, 'm:ResponseCode') ||
                     extractBetweenTags(xmlData, 'ResponseCode');

if (responseCode && responseCode !== 'NoError') {
  const messageText = extractBetweenTags(xmlData, 'm:MessageText') ||
                      extractBetweenTags(xmlData, 'MessageText') || 'Unknown EWS error';
  return [{ json: { success: false, error: responseCode, message: messageText, raw: xmlData } }];
}

// Parse CreateItem response (send/reply)
if (xmlData.includes('CreateItemResponse') || xmlData.includes('ReplyToItemResponse')) {
  return [{ json: { success: true, operation: 'created' } }];
}

// Parse FindItem response (list inbox)
if (xmlData.includes('FindItemResponse')) {
  const messages = [];
  const messageBlocks = extractAll(xmlData, 't:Message');
  for (const block of messageBlocks) {
    messages.push({      
      item_id: extractAttr(block, 't:ItemId', 'Id') || extractAttr(block, 'ItemId', 'Id'),
      change_key: extractAttr(block, 't:ItemId', 'ChangeKey'),
      subject: extractBetweenTags(block, 't:Subject') || extractBetweenTags(block, 'Subject'),
      from: (() => { 
        const f = extractBetweenTags(block, 't:From'); 
        if (!f) return null;
        const m = extractBetweenTags(f, 't:Mailbox');
        return m ? extractBetweenTags(m, 't:EmailAddress') : extractBetweenTags(f, 't:EmailAddress');
      })(),
      from_name: (() => { 
        const f = extractBetweenTags(block, 't:From'); 
        if (!f) return null;
        const m = extractBetweenTags(f, 't:Mailbox');
        return m ? extractBetweenTags(m, 't:Name') : extractBetweenTags(f, 't:Name');
      })(),
      received: extractBetweenTags(block, 't:DateTimeReceived') || extractBetweenTags(block, 'DateTimeReceived'),
      is_read: extractBetweenTags(block, 't:IsRead') || extractBetweenTags(block, 'IsRead'),
    });
  }
  return [{ json: { success: true, count: messages.length, messages } }];
}

// Parse GetItem response (full message)
if (xmlData.includes('GetItemResponse')) {
  const messageBlock = extractBetweenTags(xmlData, 't:Message') ||
                       extractBetweenTags(xmlData, 'Message');
  if (!messageBlock) return [{ json: { success: false, error: 'Could not parse message', raw: xmlData } }];

  return [{ json: {
    success: true,
    item_id: extractAttr(xmlData, 't:ItemId', 'Id'),
    subject: extractBetweenTags(xmlData, 't:Subject'),
    from_email: extractBetweenTags(xmlData, 't:EmailAddress'),
    from_name: extractBetweenTags(xmlData, 't:Name'),
    received: extractBetweenTags(xmlData, 't:DateTimeReceived'),
    body: extractBetweenTags(xmlData, 't:Body'),
    is_read: extractBetweenTags(xmlData, 't:IsRead'),
  } }];
}

// Fallback: return raw
return [{ json: { success: true, raw: xmlData } }];
